ALTER TABLE soma_quizzes ADD COLUMN IF NOT EXISTS pdf_marking_mode TEXT NOT NULL DEFAULT 'manual';
ALTER TABLE assessment_attachments ADD COLUMN IF NOT EXISTS document_role TEXT NOT NULL DEFAULT 'worksheet';
ALTER TABLE submission_uploads ADD COLUMN IF NOT EXISTS ai_marking_status TEXT;
ALTER TABLE submission_uploads ADD COLUMN IF NOT EXISTS submission_version INTEGER NOT NULL DEFAULT 1;
ALTER TABLE submission_uploads ADD COLUMN IF NOT EXISTS content_hash TEXT;
CREATE TABLE IF NOT EXISTS pdf_assessment_configs (id SERIAL PRIMARY KEY, quiz_id INTEGER NOT NULL UNIQUE REFERENCES soma_quizzes(id) ON DELETE CASCADE, primary_exam_attachment_id INTEGER REFERENCES assessment_attachments(id) ON DELETE SET NULL, preparation_status TEXT NOT NULL DEFAULT 'not_started', active_rubric_version_id INTEGER, last_error_code TEXT, last_error TEXT, prepared_at TIMESTAMPTZ, approved_at TIMESTAMPTZ, approved_by UUID REFERENCES soma_users(id) ON DELETE SET NULL, created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, updated_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS pdf_marking_documents (id SERIAL PRIMARY KEY, quiz_id INTEGER NOT NULL REFERENCES soma_quizzes(id) ON DELETE CASCADE, kind TEXT NOT NULL DEFAULT 'mark_scheme', filename TEXT NOT NULL, storage_path TEXT NOT NULL, mime_type TEXT NOT NULL, size_bytes INTEGER NOT NULL, content_hash TEXT NOT NULL, page_count INTEGER, processing_status TEXT NOT NULL DEFAULT 'uploaded', extracted_text TEXT, extraction_metadata JSONB, processing_error TEXT, uploaded_by UUID REFERENCES soma_users(id) ON DELETE SET NULL, created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, processed_at TIMESTAMPTZ);
CREATE TABLE IF NOT EXISTS pdf_rubric_versions (id SERIAL PRIMARY KEY, quiz_id INTEGER NOT NULL REFERENCES soma_quizzes(id) ON DELETE CASCADE, version INTEGER NOT NULL, source TEXT NOT NULL, status TEXT NOT NULL DEFAULT 'draft', total_marks INTEGER NOT NULL, rubric_json JSONB NOT NULL, extraction_json JSONB, model_metadata JSONB, created_by UUID REFERENCES soma_users(id) ON DELETE SET NULL, approved_by UUID REFERENCES soma_users(id) ON DELETE SET NULL, created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, approved_at TIMESTAMPTZ);
CREATE TABLE IF NOT EXISTS pdf_marking_jobs (id SERIAL PRIMARY KEY, job_type TEXT NOT NULL, idempotency_key TEXT NOT NULL UNIQUE, quiz_id INTEGER REFERENCES soma_quizzes(id) ON DELETE CASCADE, submission_upload_id INTEGER REFERENCES submission_uploads(id) ON DELETE CASCADE, rubric_version_id INTEGER REFERENCES pdf_rubric_versions(id) ON DELETE SET NULL, status TEXT NOT NULL DEFAULT 'queued', payload JSONB NOT NULL DEFAULT '{}'::jsonb, attempts INTEGER NOT NULL DEFAULT 0, max_attempts INTEGER NOT NULL DEFAULT 3, available_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, locked_at TIMESTAMPTZ, locked_by TEXT, last_error_code TEXT, last_error TEXT, created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, updated_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, completed_at TIMESTAMPTZ);
CREATE TABLE IF NOT EXISTS pdf_marking_runs (id SERIAL PRIMARY KEY, submission_upload_id INTEGER NOT NULL REFERENCES submission_uploads(id) ON DELETE CASCADE, submission_version INTEGER NOT NULL, rubric_version_id INTEGER NOT NULL REFERENCES pdf_rubric_versions(id) ON DELETE RESTRICT, status TEXT NOT NULL, input_hash TEXT NOT NULL, prompt_version TEXT NOT NULL, marker_a_provider TEXT NOT NULL, marker_a_model TEXT NOT NULL, marker_b_provider TEXT NOT NULL, marker_b_model TEXT NOT NULL, marker_a_result JSONB, marker_b_result JSONB, verifier_a_result JSONB, verifier_b_result JSONB, reconciled_result JSONB, proposed_score INTEGER, max_score INTEGER, confidence_pct INTEGER, requires_tutor_review BOOLEAN NOT NULL DEFAULT true, annotated_storage_path TEXT, failure_code TEXT, failure_message TEXT, started_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, finished_at TIMESTAMPTZ, created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS pdf_marking_review_items (id SERIAL PRIMARY KEY, run_id INTEGER NOT NULL REFERENCES pdf_marking_runs(id) ON DELETE CASCADE, question_label TEXT NOT NULL, rubric_item_id TEXT NOT NULL, reason_code TEXT NOT NULL, marker_a_decision JSONB, marker_b_decision JSONB, verifier_a_decision JSONB, verifier_b_decision JSONB, resolution_status TEXT NOT NULL DEFAULT 'pending', resolved_marks INTEGER, resolution_note TEXT, resolved_by UUID REFERENCES soma_users(id) ON DELETE SET NULL, resolved_at TIMESTAMPTZ, created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS pdf_marking_annotations (id SERIAL PRIMARY KEY, run_id INTEGER NOT NULL REFERENCES pdf_marking_runs(id) ON DELETE CASCADE, submission_upload_id INTEGER NOT NULL REFERENCES submission_uploads(id) ON DELETE CASCADE, page_number INTEGER NOT NULL, annotation_type TEXT NOT NULL, x_bp INTEGER NOT NULL, y_bp INTEGER NOT NULL, width_bp INTEGER NOT NULL, height_bp INTEGER NOT NULL, question_label TEXT NOT NULL, rubric_item_id TEXT, awarded_marks INTEGER NOT NULL, max_marks INTEGER NOT NULL, explanation TEXT NOT NULL, source TEXT NOT NULL, status TEXT NOT NULL DEFAULT 'proposed', created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, updated_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, CONSTRAINT pdf_marking_annotations_bp_check CHECK (x_bp BETWEEN 0 AND 10000 AND y_bp BETWEEN 0 AND 10000 AND width_bp BETWEEN 0 AND 10000 AND height_bp BETWEEN 0 AND 10000));
CREATE UNIQUE INDEX IF NOT EXISTS pdf_rubric_versions_quiz_version_idx ON pdf_rubric_versions(quiz_id, version);
CREATE INDEX IF NOT EXISTS pdf_marking_documents_quiz_id_idx ON pdf_marking_documents(quiz_id);
CREATE INDEX IF NOT EXISTS pdf_marking_jobs_poll_idx ON pdf_marking_jobs(available_at) WHERE status IN ('queued','retry_wait');
CREATE INDEX IF NOT EXISTS pdf_marking_jobs_submission_idx ON pdf_marking_jobs(submission_upload_id);
CREATE INDEX IF NOT EXISTS pdf_marking_runs_submission_created_idx ON pdf_marking_runs(submission_upload_id, created_at);
CREATE INDEX IF NOT EXISTS pdf_marking_review_items_run_id_idx ON pdf_marking_review_items(run_id);
CREATE INDEX IF NOT EXISTS pdf_marking_annotations_run_id_idx ON pdf_marking_annotations(run_id);
CREATE INDEX IF NOT EXISTS pdf_marking_annotations_submission_idx ON pdf_marking_annotations(submission_upload_id);
